#!/usr/bin/env dotnet

// Find the earliest Friday the 13th in the proleptic Gregorian calendar (from 0001-01-01)
// and count how many Friday the 13ths exist in a full 400-year cycle.

DateOnly earliest = DateOnly.MaxValue;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var date = new DateOnly(year, month, 13);
        if (date.DayOfWeek == DayOfWeek.Friday)
        {
            if (date < earliest)
                earliest = date;
        }
    }
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count all Friday the 13ths in a 400-year cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var date = new DateOnly(year, month, 13);
        if (date.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");
EOF
